def majority_vote(labels: List[str]) -> Tuple[Optional[str], Dict[str, int]]:
    votes: Dict[str, int] = {}
    for l in labels:
        votes[l] = votes.get(l, 0) + 1
    if not votes:
        return None, {}
    max_count = max(votes.values())
    winners = sorted([k for k, v in votes.items() if v == max_count])
    return winners[0] if winners else None, votes


def get_image_row(conn, image_id: str):
    row = conn.execute("SELECT * FROM images WHERE id = ?", (image_id,)).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="Image not found")
    return row


def get_labels_for_image(conn, image_id: str) -> List[sqlite3.Row]:
    return conn.execute(
        "SELECT * FROM labels WHERE image_id = ? ORDER BY created_at ASC",
        (image_id,),
    ).fetchall()


def aggregated_for_image(conn, image_id: str) -> AggregatedLabel:
    rows = get_labels_for_image(conn, image_id)
    labels = [r["label"] for r in rows]
    agg, votes = majority_vote(labels)
    return AggregatedLabel(
        image_id=image_id,
        label=agg,
        votes=votes,
        total_votes=len(labels),
    )


@app.post("/images", response_model=ImageCreateResponse)
async def upload_image(file: UploadFile = File(...)):
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="Only image uploads are supported")

    image_id = str(uuid.uuid4())
    filename = file.filename or f"{image_id}.img"
    ext = os.path.splitext(filename)[1].lower()
    if ext not in [".jpg", ".jpeg", ".png", ".bmp", ".webp"]:
        ext = ".png"
    stored_name = f"{image_id}{ext}"
    path = os.path.join(IMAGES_DIR, stored_name)

    data = await file.read()
    try:
        img = Image.open(io.BytesIO(data)).convert("RGB")
        img.save(path)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file")

    created_at = _utcnow_iso()
    conn = _connect()
    conn.execute(
        "INSERT INTO images (id, filename, path, created_at) VALUES (?, ?, ?, ?)",
        (image_id, filename, path, created_at),
    )
    conn.commit()
    conn.close()
    return ImageCreateResponse(image_id=image_id, filename=filename, created_at=created_at)


