class LabeledImageDataset(Dataset):
    def __init__(self, items: List[Tuple[str, int]], transform):
        self.items = items
        self.transform = transform

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx):
        path, y = self.items[idx]
        img = Image.open(path).convert("RGB")
        x = self.transform(img)
        return x, y


def _collect_training_data(conn) -> Tuple[List[Tuple[str, str]], List[str]]:
    rows = conn.execute("SELECT id, path FROM images").fetchall()
    labeled: List[Tuple[str, str]] = []
    all_labels: List[str] = []
    for r in rows:
        image_id = r["id"]
        label_rows = conn.execute("SELECT label FROM labels WHERE image_id = ?", (image_id,)).fetchall()
        labels = [lr["label"] for lr in label_rows]
        agg, _votes = majority_vote(labels)
        if agg is None:
            continue
        labeled.append((r["path"], agg))
        all_labels.append(agg)
    classes = sorted(list(set(all_labels)))
    return labeled, classes


def _train_model_job(model_id: str, epochs: int, batch_size: int, lr: float, device: str):
    conn = _connect()
    try:
        conn.execute("UPDATE models SET status = ? WHERE id = ?", ("running", model_id))
        conn.commit()

        labeled, classes = _collect_training_data(conn)
        if len(labeled) == 0:
            conn.execute(
                "UPDATE models SET status = ?, error = ?, num_images = ?, num_labels = ?, num_classes = ?, classes_json = ? WHERE id = ?",
                ("failed", "No aggregated labels available to train", 0, 0, 0, "[]", model_id),
            )
            conn.commit()
            return

        class_to_idx = {c: i for i, c in enumerate(classes)}
        items = [(path, class_to_idx[label]) for path, label in labeled]

        num_images = len(items)
        num_labels = num_images
        num_classes = len(classes)

        conn.execute(
            "UPDATE models SET num_images = ?, num_labels = ?, num_classes = ?, classes_json = ? WHERE id = ?",
            (num_images, num_labels, num_classes, json.dumps(classes), model_id),
        )
        conn.commit()

        transform = transforms.Compose(
            [
                transforms.Resize((224, 224)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
            ]
        )

        ds = LabeledImageDataset(items, transform)
        dl = DataLoader(ds, batch_size=batch_size, shuffle=True, num_workers=TRAIN_NUM_WORKERS)

        model = models.resnet18(weights=models.ResNet18_Weights.DEFAULT)
        model.fc = nn.Linear(model.fc.in_features, num_classes)
        model = model.to(device)

        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=lr)

        model.train()
        for _epoch in range(epochs):
            for xb, yb in dl:
                xb = xb.to(device, non_blocking=True)
                yb = yb.to(device, non_blocking=True)
                optimizer.zero_grad(set_to_none=True)
                logits = model(xb)
                loss = criterion(logits, yb)
                loss.backward()
                optimizer.step()

        ts = int(time.time())
        model_path = os.path.join(MODEL_DIR, f"{model_id}_{ts}.pt")
        payload = {
            "state_dict": model.state_dict(),
            "classes": classes,
            "arch": "resnet18",
            "created_at": _utcnow_iso(),
        }
        torch.save(payload, model_path)

        conn.execute(
            "UPDATE models SET status = ?, model_path = ? WHERE id = ?",
            ("succeeded", model_path, model_id),
        )
        conn.commit()
    except Exception as e:
        conn.execute(
            "UPDATE models SET status = ?, error = ? WHERE id = ?",
            ("failed", str(e), model_id),
        )
        conn.commit()
    finally:
        conn.close()


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    epochs = int(req.epochs) if req.epochs is not None else TRAIN_EPOCHS
    batch_size = int(req.batch_size) if req.batch_size is not None else TRAIN_BATCH_SIZE
    lr = float(req.lr) if req.lr is not None else TRAIN_LR
    device = req.device or TRAIN_DEVICE

    if epochs <= 0 or batch_size <= 0 or lr <= 0:
        raise HTTPException(status_code=400, detail="Invalid training hyperparameters")

    model_id = str(uuid.uuid4())
    created_at = _utcnow_iso()

    conn = _connect()
    conn.execute(
        "INSERT INTO models (id, created_at, status, num_images, num_labels, num_classes, classes_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (model_id, created_at, "queued", 0, 0, 0, "[]"),
    )
    conn.commit()
    conn.close()

    def runner():
        with TRAIN_LOCK:
            _train_model_job(model_id, epochs, batch_size, lr, device)

    t = threading.Thread(target=runner, daemon=True)
    t.start()

    return TrainResponse(model_id=model_id, status="queued")


