@app.get("/models/{model_id}/file")
def download_model(model_id: str):
    conn = _connect()
    r = conn.execute("SELECT * FROM models WHERE id = ?", (model_id,)).fetchone()
    conn.close()
    if not r:
        raise HTTPException(status_code=404, detail="Model not found")
    if r["status"] != "succeeded" or not r["model_path"]:
        raise HTTPException(status_code=400, detail="Model not available")
    if not os.path.exists(r["model_path"]):
        raise HTTPException(status_code=404, detail="Model file missing")
    return FileResponse(r["model_path"], media_type="application/octet-stream", filename=os.path.basename(r["model_path"]))


